import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Login from './features/auth/Login';
import Register from './features/auth/Register';
import MovieList from './features/movies/MovieList';
import MovieDetails from './features/movies/MovieDetails';
import Subscription from './features/subscription/Subscription';
import Profile from './features/profile/Profile';
import Watchlist from './features/watchlist/Watchlist';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    // Check if user is logged in on app load
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (token && userData) {
      setIsLoggedIn(true);
      setUser(JSON.parse(userData));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsLoggedIn(false);
    setUser(null);
    window.location.href = '/';
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      // Navigate to search results or filter movies
      window.location.href = `/?search=${encodeURIComponent(searchQuery.trim())}`;
    }
  };

  return (
    <Router>
      <div className="App">
        <nav className="netflix-nav">
          <div className="nav-left">
            <Link to="/" className="netflix-logo">NETFLIX</Link>
            <div className="nav-links">
              <Link to="/">Home</Link>
              <Link to="/tv-shows">TV Shows</Link>
              <Link to="/movies">Movies</Link>
              <Link to="/watchlist">My List</Link>
            </div>
          </div>
          <div className="nav-right">
            <form onSubmit={handleSearch} className="search-form">
              <input
                type="text"
                placeholder="Search movies..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="search-input"
              />
              <button type="submit" className="search-btn">
                🔍
              </button>
            </form>
            <div className="notifications">🔔</div>
            <div className="profile-icon">👤</div>
            <div className="auth-links">
              {isLoggedIn ? (
                <>
                  <span className="welcome-text">Welcome, {user?.name?.split(' ')[0] || 'User'}!</span>
                  <Link to="/subscription" className="auth-link">Subscription</Link>
                  <Link to="/profile" className="auth-link">Profile</Link>
                  <button onClick={handleLogout} className="auth-link logout-btn">Logout</button>
                </>
              ) : (
                <>
                  <Link to="/login" className="auth-link">Login</Link>
                  <Link to="/register" className="auth-link">Register</Link>
                  <Link to="/subscription" className="auth-link">Subscription</Link>
                </>
              )}
            </div>
          </div>
        </nav>

        <Routes>
          <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} setUser={setUser} />} />
          <Route path="/register" element={<Register setIsLoggedIn={setIsLoggedIn} setUser={setUser} />} />
          <Route path="/movie/:id" element={<MovieDetails />} />
          <Route path="/subscription" element={<Subscription />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/watchlist" element={<Watchlist />} />
          <Route path="/" element={<MovieList searchQuery={searchQuery} />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
